import { Link } from "react-router-dom";

function Tarjeta(props) {

  return (
    <div className="tarjeta">
      <img src={props.img} alt={props.titulo} />
      <div className="tarjeta-cont">
        <div className="texto-tarjeta">
          <h3>{props.titulo}</h3>
          <p>{props.precio}</p>
        </div>
        <div className="button-cont">
          <button><Link to={`/Productos/${props.id}`}>Ver Más...</Link></button>
          <button><img src="/add-carrito.svg" alt="Carrito" /></button>
        </div>
      </div>
    </div>
  );
};

export default Tarjeta;
